// Per-run constants: run id, output dir, models, and the Dylan Dog style
// prompts (ported from Styles/dylan-dog.md + src/agents/*.py).
// Edit here to change style, models, or pacing.
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const runid = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

const imageSuffix =
  'Black and white only, absolutely no color. Italian noir comic book style, detailed pen and ink artwork, heavy crosshatching, deep shadow areas, dramatic chiaroscuro lighting, 1980s graphic novel aesthetic. Urban gothic London atmosphere, rain-slicked cobblestones, Victorian architecture, cinematic panel composition, moody and atmospheric. ' +
  'No text, no speech bubbles, no captions, no letters, no words, no numbers visible anywhere in the image.';

const ideaSystem =
  'You invent premises for one-page horror/noir comics in the Dylan Dog tradition — gothic, melancholic, monsters as metaphors for grief and loss. Respond with exactly ONE original story premise as a single sentence. No quotes, no preamble, no explanation.';

const plotSystem =
  'You are a horror/noir comic book director in the Dylan Dog tradition. Given a story idea, create a comic outline that is dark, dread-laden, and Gothic — fog-choked streets, monsters as metaphors for grief and loss, beauty tarnished by horror.\n' +
  'Respond ONLY with a single compact JSON object — no markdown fences, no explanation.\n' +
  'The JSON must have exactly these fields:\n' +
  '{"title": "short punchy story title", "tagline": "one sentence — the hook", "panel_count": <integer 4-12>, "beats": [{"index": 0, "beat": "one short sentence describing what happens in this scene"}, ...]}\n' +
  'beats must have exactly panel_count items, indexed 0 to panel_count-1. Each beat is ONE short sentence.';

const sceneSystem =
  'You are a noir comic book artist working in the Dylan Dog tradition. Expand a story beat into a visual panel description.\n' +
  'The image_prompt describes only what is seen: composition, environment, mood, camera angle. Describe dramatic tension through shadows, rain, fog, body language, and environment — not graphic content.\n' +
  'Respond ONLY with compact JSON, no markdown fences:\n' +
  '{"caption": "one short atmospheric narration sentence", "dialogue": "one short spoken line, or empty string if none", "image_prompt": "visual scene description under 50 words — focus on setting, lighting, character expression, and mood. Avoid explicit violence; convey tension atmospherically."}';

const musicMood = 'dark horror noir, slow suspenseful strings, ominous piano, cinematic dread';

return [{ json: {
  runid,
  dir: `/project/output/n8n/run-${runid}`,
  panelSeconds: 3,
  model: 'claude-sonnet-4-6',
  imageModel: 'fal-ai/bytedance/seedream/v4/text-to-image',
  imageSize: 'square_hd',
  musicModel: 'fal-ai/stable-audio-3/medium/text-to-audio',
  imageSuffix, ideaSystem, plotSystem, sceneSystem, musicMood,
} }];

const idea = $json.content[0].text.trim();
if (!idea) throw new Error('Claude returned an empty idea');
return [{ json: { idea } }];

